--
-- Name: definir_meu_ponto_pin(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.definir_meu_ponto_pin(pin_plain text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
declare
  v_tem boolean;
begin
  if not public._validar_pin_quatro_digitos(pin_plain) then
    raise exception 'PIN inválido: use exactamente 4 dígitos.';
  end if;
  select (ponto_pin_hash is not null and char_length(trim(ponto_pin_hash)) > 0)
  into v_tem
  from public.profiles
  where auth_user_id = auth.uid();
  if not found then
    raise exception 'Perfil não encontrado.';
  end if;
  if v_tem then
    raise exception 'Já tem um PIN definido. Utilize a opção para alterar o PIN.';
  end if;
  update public.profiles
  set
    ponto_pin_hash = crypt(pin_plain, gen_salt('bf', 8)),
    updated_at = now()
  where auth_user_id = auth.uid();
  if not found then
    raise exception 'Perfil não encontrado.';
  end if;
end;
$$;


ALTER FUNCTION public.definir_meu_ponto_pin(pin_plain text) OWNER TO supabase_admin;

--
-- Name: fn_movimentos_tesouraria_atualiza_saldo(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_movimentos_tesouraria_atualiza_saldo() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  delta numeric;
begin
  if tg_op = 'DELETE' then
    if old.conta_bancaria_id is not null then
      delta := case when old.tipo = 'entrada' then -old.valor else old.valor end;
      update public.contas_bancarias
      set saldo_actual = saldo_actual + delta, updated_at = now()
      where id = old.conta_bancaria_id;
    end if;
    return old;
  elsif tg_op = 'INSERT' then
    if new.conta_bancaria_id is not null then
      delta := case when new.tipo = 'entrada' then new.valor else -new.valor end;
      update public.contas_bancarias
      set saldo_actual = saldo_actual + delta, updated_at = now()
      where id = new.conta_bancaria_id;
    end if;
    return new;
  elsif tg_op = 'UPDATE' then
    if old.conta_bancaria_id is not null then
      delta := case when old.tipo = 'entrada' then -old.valor else old.valor end;
      update public.contas_bancarias
      set saldo_actual = saldo_actual + delta, updated_at = now()
      where id = old.conta_bancaria_id;
    end if;
    if new.conta_bancaria_id is not null then
      delta := case when new.tipo = 'entrada' then new.valor else -new.valor end;
      update public.contas_bancarias
      set saldo_actual = saldo_actual + delta, updated_at = now()
      where id = new.conta_bancaria_id;
    end if;
    return new;
  end if;
  return new;
end;
$$;


ALTER FUNCTION public.fn_movimentos_tesouraria_atualiza_saldo() OWNER TO supabase_admin;

--
-- Name: fn_movimentos_tesouraria_check_conta(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_movimentos_tesouraria_check_conta() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  if new.conta_bancaria_id is not null then
    if not exists (
      select 1
      from public.contas_bancarias c
      where c.id = new.conta_bancaria_id
        and c.empresa_id = new.empresa_id
    ) then
      raise exception 'conta_bancaria_id deve pertencer à mesma empresa do movimento';
    end if;
  end if;
  return new;
end;
$$;


ALTER FUNCTION public.fn_movimentos_tesouraria_check_conta() OWNER TO supabase_admin;

--
-- Name: gestao_documento_pode_ler(bigint, text[], text[]); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.gestao_documento_pode_ler(p_empresa_id bigint, p_modulos text[], p_sectores text[]) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  select exists (
    select 1
    from public.profiles p
    where p.auth_user_id = auth.uid()
      and (
        (p.perfil in ('Admin', 'PCA') and p.empresa_id is null)
        or (
          p.empresa_id is not null
          and p.empresa_id = p_empresa_id
          and (
            p.perfil in ('Admin', 'PCA', 'Secretaria', 'Director')
            or (
              cardinality(coalesce(p_modulos, '{}')) = 0
              or coalesce(p.modulos, '{}') && coalesce(p_modulos, '{}')
              or (
                p.modulos is null
                and (
                  ('financas' = any (coalesce(p_modulos, '{}')) and p.perfil in ('Financeiro'))
                  or ('contabilidade' = any (coalesce(p_modulos, '{}')) and p.perfil in ('Contabilidade', 'Financeiro'))
                  or ('capital-humano' = any (coalesce(p_modulos, '{}')) and p.perfil in ('RH'))
                  or ('juridico' = any (coalesce(p_modulos, '{}')) and p.perfil in ('Juridico'))
                  or ('secretaria' = any (coalesce(p_modulos, '{}')) and p.perfil in ('Secretaria'))
                  or ('planeamento' = any (coalesce(p_modulos, '{}')) and p.perfil in ('Planeamento'))
                  or ('comunicacao-interna' = any (coalesce(p_modulos, '{}')) and p.perfil not in ('Colaborador'))
                  or ('conselho-administracao' = any (coalesce(p_modulos, '{}')) and p.perfil in ('PCA'))
                )
              )
            )
            and (
              cardinality(coalesce(p_sectores, '{}')) = 0
              or nullif(trim(p.departamento), '') is null
              or trim(p.departamento) = any (select unnest(coalesce(p_sectores, '{}')))
            )
          )
        )
      )
  );
$$;


ALTER FUNCTION public.gestao_documento_pode_ler(p_empresa_id bigint, p_modulos text[], p_sectores text[]) OWNER TO supabase_admin;

