CREATE TABLE public.intranet_chat_messages (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    conversation_id uuid NOT NULL,
    sender_profile_id bigint NOT NULL,
    content text NOT NULL,
    attachments jsonb DEFAULT '[]'::jsonb NOT NULL,
    read_by_profile_ids bigint[] DEFAULT '{}'::bigint[] NOT NULL,
    pinned boolean DEFAULT false NOT NULL,
    pinned_at timestamp with time zone,
    pinned_by_profile_id bigint,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE public.intranet_chat_messages OWNER TO supabase_admin;

--
-- Name: TABLE intranet_chat_messages; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON TABLE public.intranet_chat_messages IS 'Mensagens do chat intranet; attachments = JSON array de anexos.';


--
-- Name: intranet_chat_latest_messages(uuid[]); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.intranet_chat_latest_messages(p_conversation_ids uuid[]) RETURNS SETOF public.intranet_chat_messages
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  select distinct on (m.conversation_id) m.*
  from public.intranet_chat_messages m
  inner join public.intranet_chat_conversations c on c.id = m.conversation_id
  inner join public.profiles p on p.auth_user_id = auth.uid()
    and p.id = any (c.participant_ids)
  where m.conversation_id = any (p_conversation_ids)
  order by m.conversation_id, m.created_at desc, m.id desc;
$$;


ALTER FUNCTION public.intranet_chat_latest_messages(p_conversation_ids uuid[]) OWNER TO supabase_admin;

--
-- Name: FUNCTION intranet_chat_latest_messages(p_conversation_ids uuid[]); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.intranet_chat_latest_messages(p_conversation_ids uuid[]) IS 'Última mensagem por conversa (sidebar); só conversas em que o utilizador participa.';


--
-- Name: intranet_chat_mark_conversation_read(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.intranet_chat_mark_conversation_read(p_conversation_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_pid bigint;
begin
  select p.id into v_pid
  from public.profiles p
  where p.auth_user_id = auth.uid()
  limit 1;

  if v_pid is null then
    raise exception 'not authenticated';
  end if;

  if not exists (
    select 1
    from public.intranet_chat_conversations c
    where c.id = p_conversation_id
      and v_pid = any (c.participant_ids)
  ) then
    raise exception 'forbidden';
  end if;

  update public.intranet_chat_messages m
  set read_by_profile_ids =
    case
      when v_pid = any (m.read_by_profile_ids) then m.read_by_profile_ids
      else m.read_by_profile_ids || v_pid
    end
  where m.conversation_id = p_conversation_id
    and m.sender_profile_id is distinct from v_pid;
end;
$$;


ALTER FUNCTION public.intranet_chat_mark_conversation_read(p_conversation_id uuid) OWNER TO supabase_admin;

--
-- Name: intranet_chat_unread_summary(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.intranet_chat_unread_summary() RETURNS TABLE(conversation_id uuid, unread_count bigint)
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  with me as (
    select p.id as profile_id
    from public.profiles p
    where p.auth_user_id = auth.uid()
    limit 1
  )
  select m.conversation_id, count(*)::bigint as unread_count
  from public.intranet_chat_messages m
  inner join public.intranet_chat_conversations c on c.id = m.conversation_id
  cross join me
  where me.profile_id = any (c.participant_ids)
    and m.sender_profile_id is distinct from me.profile_id
    and not (me.profile_id = any (m.read_by_profile_ids))
  group by m.conversation_id;
$$;


ALTER FUNCTION public.intranet_chat_unread_summary() OWNER TO supabase_admin;

--
-- Name: FUNCTION intranet_chat_unread_summary(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.intranet_chat_unread_summary() IS 'Contagem de mensagens não lidas por conversa (para o utilizador actual).';


