--
-- Name: set_my_pin(text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.set_my_pin(new_pin text, current_pin text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $_$
declare
  h text;
begin
  if new_pin is null or length(new_pin) <> 4 or new_pin !~ '^[0-9]{4}$' then
    raise exception 'PIN deve ter exactamente 4 dígitos numéricos';
  end if;

  select p.pin_hash into h
  from public.profiles p
  where p.auth_user_id = auth.uid();

  if not found then
    raise exception 'Perfil não encontrado';
  end if;

  if h is not null and length(trim(h)) > 0 then
    if current_pin is null or length(current_pin) <> 4 or current_pin !~ '^[0-9]{4}$' then
      raise exception 'Indique o PIN atual para alterar';
    end if;
    if h <> extensions.crypt(current_pin, h) then
      raise exception 'PIN atual incorreto';
    end if;
  end if;

  update public.profiles
  set pin_hash = extensions.crypt(new_pin, extensions.gen_salt('bf'::text))
  where auth_user_id = auth.uid();
end;
$_$;


ALTER FUNCTION public.set_my_pin(new_pin text, current_pin text) OWNER TO supabase_admin;

