    audio_transcricao_path text,
    participantes_nomes text[] DEFAULT '{}'::text[] NOT NULL,
    CONSTRAINT actas_status_check CHECK ((status = ANY (ARRAY['Rascunho'::text, 'Em Revisão'::text, 'Aprovada'::text, 'Publicada'::text, 'Arquivada'::text])))
);


