-- Name: profiles; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.profiles (
    id bigint NOT NULL,
    auth_user_id uuid NOT NULL,
    nome text NOT NULL,
    email text NOT NULL,
    perfil text NOT NULL,
    cargo text DEFAULT ''::text,
    departamento text DEFAULT ''::text,
    avatar text DEFAULT '?'::text,
    permissoes text[] DEFAULT '{}'::text[],
    modulos text[],
    colaborador_id bigint,
    empresa_id bigint,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    assinatura_linha text,
    assinatura_cargo text,
    assinatura_imagem_url text,
    pin_hash text,
    username text NOT NULL,
    numero_mec text,
    ponto_pin_hash text,
    primeiro_acesso_pendente boolean DEFAULT false NOT NULL
);


ALTER TABLE public.profiles OWNER TO postgres;

--
-- Name: TABLE profiles; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON TABLE public.profiles IS 'Perfis de utilizador do SANEP (ligados a auth.users).';


--
-- Name: COLUMN profiles.pin_hash; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.profiles.pin_hash IS 'bcrypt hash do PIN de 4 dígitos; gerido só via RPC';


--
-- Name: COLUMN profiles.username; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.profiles.username IS 'Nome de utilizador único para login (Supabase Auth usa o email internamente).';


--
-- Name: COLUMN profiles.numero_mec; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.profiles.numero_mec IS 'Número mecanográfico alinhado a colaboradores.numero_mec; usado em RLS de marcação de ponto (sem depender de colaborador_id).';


--
-- Name: COLUMN profiles.ponto_pin_hash; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.profiles.ponto_pin_hash IS 'bcrypt (pgcrypto) do PIN de 4 dígitos para ponto; usar apenas RPCs.';


--
-- Name: COLUMN profiles.primeiro_acesso_pendente; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.profiles.primeiro_acesso_pendente IS 'Se true (tipicamente Colaborador recém-criado), a app exige alterar senha e definir PIN antes de continuar.';


