    status text DEFAULT 'Rascunho'::text NOT NULL,
    actividades_comerciais text DEFAULT ''::text NOT NULL,
    principais_constrangimentos text DEFAULT ''::text NOT NULL,
    estrategias_receitas text DEFAULT ''::text NOT NULL,
    estrategias_custos text DEFAULT ''::text NOT NULL,
