    vendas_produtos jsonb DEFAULT '[]'::jsonb NOT NULL,
    vendas_servicos jsonb DEFAULT '[]'::jsonb NOT NULL,
    custo_mercadorias_vendidas jsonb DEFAULT '[]'::jsonb NOT NULL,
    fornecimento_servicos_externos jsonb DEFAULT '[]'::jsonb NOT NULL,
