--
-- Name: profiles Admin pode apagar qualquer perfil; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Admin pode apagar qualquer perfil" ON public.profiles FOR DELETE TO authenticated USING (public.current_user_is_admin());


--
-- Name: profiles Admin pode atualizar qualquer perfil; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Admin pode atualizar qualquer perfil" ON public.profiles FOR UPDATE TO authenticated USING (public.current_user_is_admin()) WITH CHECK (public.current_user_is_admin());


--
-- Name: profiles Admin pode ler todos os perfis; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Admin pode ler todos os perfis" ON public.profiles FOR SELECT TO authenticated USING (public.current_user_is_admin());


--
-- Name: profiles Autenticados podem listar perfis (directório interno); Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Autenticados podem listar perfis (directório interno)" ON public.profiles FOR SELECT TO authenticated USING ((auth.uid() IS NOT NULL));


--
-- Name: POLICY "Autenticados podem listar perfis (directório interno)" ON profiles; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON POLICY "Autenticados podem listar perfis (directório interno)" ON public.profiles IS 'Permite listar todos os perfis com sessão (chat, dropdowns). Dados já visíveis na intranet.';


