--

CREATE POLICY "Utilizador pode atualizar o próprio perfil" ON public.profiles FOR UPDATE USING ((auth.uid() = auth_user_id));


--
-- Name: profiles Utilizador pode ler o próprio perfil; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Utilizador pode ler o próprio perfil" ON public.profiles FOR SELECT USING ((auth.uid() = auth_user_id));


--
-- Name: aniversario_parabens; Type: ROW SECURITY; Schema: public; Owner: supabase_admin
--

ALTER TABLE public.aniversario_parabens ENABLE ROW LEVEL SECURITY;

--
-- Name: aniversario_parabens aniversario_parabens: autor delete; Type: POLICY; Schema: public; Owner: supabase_admin
--

CREATE POLICY "aniversario_parabens: autor delete" ON public.aniversario_parabens FOR DELETE USING ((EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.auth_user_id = auth.uid()) AND (p.colaborador_id IS NOT NULL) AND (p.colaborador_id = aniversario_parabens.autor_colaborador_id)))));


--
-- Name: aniversario_parabens aniversario_parabens: colaborador insert; Type: POLICY; Schema: public; Owner: supabase_admin
--

CREATE POLICY "aniversario_parabens: colaborador insert" ON public.aniversario_parabens FOR INSERT WITH CHECK (((EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.auth_user_id = auth.uid()) AND (p.colaborador_id IS NOT NULL) AND (p.colaborador_id = aniversario_parabens.autor_colaborador_id)))) AND (EXISTS ( SELECT 1
   FROM (public.colaboradores c_a
     JOIN public.colaboradores c_d ON ((c_d.id = aniversario_parabens.destinatario_colaborador_id)))
  WHERE ((c_a.id = aniversario_parabens.autor_colaborador_id) AND (c_a.empresa_id = c_d.empresa_id) AND (c_a.empresa_id = aniversario_parabens.empresa_id)))) AND (EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.auth_user_id = auth.uid()) AND (((p.perfil = ANY (ARRAY['Admin'::text, 'PCA'::text])) AND (p.empresa_id IS NULL)) OR ((p.empresa_id IS NOT NULL) AND (p.empresa_id = aniversario_parabens.empresa_id)))))) AND (EXISTS ( SELECT 1
   FROM public.colaboradores c
  WHERE ((c.id = aniversario_parabens.destinatario_colaborador_id) AND (c.data_nascimento IS NOT NULL) AND (to_char((c.data_nascimento)::timestamp with time zone, 'MM-DD'::text) = to_char(((timezone('Africa/Luanda'::text, now()))::date)::timestamp with time zone, 'MM-DD'::text)))))));


--
-- Name: aniversario_parabens aniversario_parabens: tenant select; Type: POLICY; Schema: public; Owner: supabase_admin
--

CREATE POLICY "aniversario_parabens: tenant select" ON public.aniversario_parabens FOR SELECT USING ((EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.auth_user_id = auth.uid()) AND (((p.perfil = ANY (ARRAY['Admin'::text, 'PCA'::text])) AND (p.empresa_id IS NULL)) OR ((p.empresa_id IS NOT NULL) AND (p.empresa_id = aniversario_parabens.empresa_id)))))));


