   FROM public.profiles p
  WHERE ((p.auth_user_id = auth.uid()) AND (p.perfil = 'Admin'::text)))));


--
-- Name: bancos bancos: admin update; Type: POLICY; Schema: public; Owner: supabase_admin
--

CREATE POLICY "bancos: admin update" ON public.bancos FOR UPDATE USING ((EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.auth_user_id = auth.uid()) AND (p.perfil = 'Admin'::text))))) WITH CHECK ((EXISTS ( SELECT 1
   FROM public.profiles p
