--
-- Name: biometrico_registros biometrico_registros_insert_own_numero_mec; Type: POLICY; Schema: public; Owner: supabase_admin
--

CREATE POLICY biometrico_registros_insert_own_numero_mec ON public.biometrico_registros FOR INSERT TO authenticated WITH CHECK ((EXISTS ( SELECT 1
   FROM (public.profiles p
     JOIN public.colaboradores c ON ((lower(TRIM(BOTH FROM c.numero_mec)) = lower(TRIM(BOTH FROM p.numero_mec)))))
  WHERE ((p.auth_user_id = auth.uid()) AND (p.numero_mec IS NOT NULL) AND (TRIM(BOTH FROM p.numero_mec) <> ''::text) AND (c.numero_mec IS NOT NULL) AND (TRIM(BOTH FROM c.numero_mec) <> ''::text) AND (lower(TRIM(BOTH FROM (biometrico_registros.numero_mec)::text)) = lower(TRIM(BOTH FROM p.numero_mec))) AND ((TRIM(BOTH FROM COALESCE(biometrico_registros.empresa, ''::text)) = ''::text) OR (EXISTS ( SELECT 1
           FROM public.empresas e
          WHERE ((e.id = c.empresa_id) AND (lower(TRIM(BOTH FROM biometrico_registros.empresa)) = lower(TRIM(BOTH FROM e.nome))))))) AND ((p.empresa_id IS NULL) OR (NOT (p.empresa_id IS DISTINCT FROM c.empresa_id)))))));


--
-- Name: biometrico_registros biometrico_registros_select_rh_tenant; Type: POLICY; Schema: public; Owner: supabase_admin
--

CREATE POLICY biometrico_registros_select_rh_tenant ON public.biometrico_registros FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.auth_user_id = auth.uid()) AND (((p.perfil = ANY (ARRAY['Admin'::text, 'PCA'::text])) AND (p.empresa_id IS NULL)) OR ((p.perfil = ANY (ARRAY['Admin'::text, 'RH'::text, 'PCA'::text])) AND (p.empresa_id IS NOT NULL) AND (biometrico_registros.numero_mec IS NOT NULL) AND (TRIM(BOTH FROM (biometrico_registros.numero_mec)::text) <> ''::text) AND (EXISTS ( SELECT 1
           FROM public.colaboradores c
          WHERE ((c.numero_mec IS NOT NULL) AND (TRIM(BOTH FROM c.numero_mec) <> ''::text) AND (lower(TRIM(BOTH FROM c.numero_mec)) = lower(TRIM(BOTH FROM (biometrico_registros.numero_mec)::text))) AND (c.empresa_id = p.empresa_id))))))))));


